// Exclude rows already sent. Aggressive email trim (spaces, NBSP, zero-width) so SMTP never sees bad addresses.
function cleanStr(v) {
  if (v === null || v === undefined) return v;
  if (typeof v !== 'string') {
    if (typeof v === 'number' && !Number.isNaN(v)) v = String(v);
    else return v;
  }
  return v.replace(/[\u200B-\u200D\uFEFF]/g, '').replace(/\u00A0/g, ' ').trim();
}
function cleanEmail(v) {
  if (v === null || v === undefined) return '';
  return String(v).replace(/[\u200B-\u200D\uFEFF]/g, '').replace(/\u00A0/g, ' ').trim();
}
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const j = { ...(items[i].json || {}) };
  for (const k of Object.keys(j)) {
    if (typeof j[k] === 'string') j[k] = cleanStr(j[k]);
  }
  if ('Email' in j) j['Email'] = cleanEmail(j['Email']);
  if ('email' in j) j['email'] = cleanEmail(j['email']);
  for (const k of Object.keys(j)) {
    if (/^email$/i.test(k.trim())) j[k] = cleanEmail(j[k]);
  }
  const sheetRow = j['Row'] ?? j['row'];
  j.Row = (sheetRow !== undefined && sheetRow !== null && sheetRow !== '') ? Number(sheetRow) : (2 + i);
  let sentVal = j['Email Sent'] ?? j['Email  Sent'] ?? j['email sent'] ?? '';
  if (sentVal === undefined || sentVal === null) {
    const key = Object.keys(j).find(k => k !== 'Row' && /email\s*sent/i.test(String(k).trim()));
    sentVal = key ? j[key] : '';
  }
  const sent = String(sentVal).toLowerCase().trim();
  if (sent === 'sent') continue;
  out.push({ json: j, pairedItem: { item: i } });
}
return out;

// Merge Subject and Body; normalize email again + _toEmail for SMTP (never spaces in To:).
function cleanEmail(v) {
  if (v === null || v === undefined) return '';
  return String(v).replace(/[\u200B-\u200D\uFEFF]/g, '').replace(/\u00A0/g, ' ').trim();
}
function cleanEmailList(v) {
  return String(v || '')
    .split(/[;,]/)
    .map(cleanEmail)
    .filter(Boolean)
    .join(', ');
}
function normalizeKey(key) {
  return String(key || '').trim().toLowerCase().replace(/[^a-z0-9]+/g, '');
}
function escapeRegExp(str) {
  return String(str).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}
function replacePlaceholderCI(text, key, value) {
  const pattern = new RegExp('\\{\\{\\s*' + escapeRegExp(key) + '\\s*\\}\\}', 'gi');
  return String(text).replace(pattern, String(value));
}
const staticData = $getWorkflowStaticData('global');
const DEFAULT_SHEET_URL = 'https://docs.google.com/spreadsheets/d/1sUUpVcRs5tE1KzNGaVA4cnQShvr1eI1bvkO44jAsKtI/edit?gid=0#gid=0';
const body = (staticData.sendmailsCampaign && typeof staticData.sendmailsCampaign === 'object') ? staticData.sendmailsCampaign : {};
const sheetKey = String(body.sheetUrl || DEFAULT_SHEET_URL).trim();
const stopMap = (staticData.sendmailsStopMap && typeof staticData.sendmailsStopMap === 'object') ? staticData.sendmailsStopMap : {};
if (sheetKey && stopMap[sheetKey]) {
  return null;
}
let subject = String(body.subject ?? '');
let html = String(body.bodyHtml ?? '');
const row = { ...$input.item.json };
if ('Email' in row) row.Email = cleanEmail(row.Email);
if ('email' in row) row.email = cleanEmail(row.email);
const _toEmail = cleanEmail(row.Email || row.email);
const _ccEmail = cleanEmailList(body.cc ?? '');
const rowKeyByNormalized = {};
for (const key of Object.keys(row)) {
  const nk = normalizeKey(key);
  if (nk && !rowKeyByNormalized[nk]) rowKeyByNormalized[nk] = key;
}
function getRowValueByAliases(aliases) {
  for (const alias of aliases) {
    const key = rowKeyByNormalized[normalizeKey(alias)];
    if (!key) continue;
    const value = row[key];
    if (value !== null && value !== undefined && String(value).trim() !== '') return value;
  }
  return null;
}
const courseValue = getRowValueByAliases(['course', 'course_name', 'courseid', 'coures']);
if (courseValue !== null) {
  for (const alias of ['course', 'course_name', 'coures']) {
    subject = replacePlaceholderCI(subject, alias, courseValue);
    html = replacePlaceholderCI(html, alias, courseValue);
  }
}
for (const [k, v] of Object.entries(row)) {
  if (v === null || v === undefined) continue;
  subject = replacePlaceholderCI(subject, k, v);
  html = replacePlaceholderCI(html, k, v);
}
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!_toEmail || !EMAIL_RE.test(_toEmail)) return [];
subject = subject.replace(/\s+/g, ' ').trim();
const FOOTER_MARKER = 'data-sbs-deliverability-footer';
const footerHtml = '<div ' + FOOTER_MARKER + '="1" style="margin-top:24px;padding-top:16px;border-top:1px solid #e5e7eb;font-size:12px;line-height:1.5;color:#6b7280;">' +
  '<p><strong>SBS – Sustainable Business Solutions</strong><br>' +
  'Email: <a href="mailto:info@sbsolutions-eg.com">info@sbsolutions-eg.com</a></p>' +
  '<p>If you no longer wish to receive these emails, reply with &quot;Unsubscribe&quot; in the subject line.</p></div>';
if (!html.includes(FOOTER_MARKER)) html = html.trim() + footerHtml;
function htmlToPlain(s) {
  return String(s).replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '').replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n').replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ').replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\n{3,}/g, '\n\n').trim();
}
const _textPlain = htmlToPlain(html);
return { json: { ...row, _subject: subject, _html: html, _textPlain, _toEmail, _ccEmail } };

// Email Sent = Error + store SMTP/n8n error text in column "Send Error" (add this column to your sheet).
const j = { ...($input.item.json || {}) };
let msg = '';
const e = j.error;
if (e && typeof e === 'object' && e.message) msg = String(e.message);
else if (typeof e === 'string') msg = e;
if (!msg && j.message && typeof j.message === 'string') {
  const looksLikeRow = j.Email != null || j.email != null || j.Name != null;
  if (!looksLikeRow || String(j.message).length < 200) msg = String(j.message);
}
if (!msg) {
  try {
    const se = $('Send Email (Zoho SMTP)').item?.json;
    if (se?.error?.message) msg = String(se.error.message);
    else if (typeof se?.error === 'string') msg = se.error;
  } catch (_) {}
}
if (!msg) msg = 'Send failed — open this execution in n8n to see the error.';
j['Email Sent'] = 'Error';
j['Send Error'] = msg.replace(/\s+/g, ' ').trim().slice(0, 500);
delete j.error;
const staticData = $getWorkflowStaticData('global');
const sheetKey = String(staticData.sendmailsCampaign?.sheetUrl || '').trim();
if (!staticData.sendmailsLastErrorMap || typeof staticData.sendmailsLastErrorMap !== 'object') {
  staticData.sendmailsLastErrorMap = {};
}
if (sheetKey) {
  staticData.sendmailsLastErrorMap[sheetKey] = {
    message: j['Send Error'],
    row: j['row_number'] ?? j['Row'] ?? null,
    at: new Date().toISOString(),
  };
}
return { json: j };

const items = $input.all();
if (items.length === 0) return [{ json: { columns: [], sampleRow: {}, error: 'No data' } }];
const first = items[0].json;
const columns = Object.keys(first);
const sampleRow = { ...first };
return [{ json: { columns, sampleRow } }];

// Count sent vs pending/errors from sheet for dashboard status.
const items = $input.all();
let sent = 0;
let pending = 0;
let errors = 0;
let lastSentRow = 0;
let lastError = '';
let lastErrorRow = 0;
const emailSentKey = (row) => {
  const k = Object.keys(row).find(key => key !== 'Row' && key !== 'row_number' && /email\s*sent/i.test(String(key).trim()));
  return k || 'Email Sent';
};
const sendErrorKey = (row) => {
  const k = Object.keys(row).find(key => key !== 'Row' && key !== 'row_number' && /send\s*error/i.test(String(key).trim()));
  return k || 'Send Error';
};
const emailVal = (row) => String((row['Email'] ?? row['email'] ?? '')).trim();
const isRateLimitMsg = (msg) => {
  const m = String(msg || '').toLowerCase();
  return (
    m.includes('mail rate exceeded') ||
    m.includes('rate exceeded limit') ||
    m.includes('5.4.6') ||
    m.includes('unusual sending') ||
    m.includes('sending limit') ||
    m.includes('daily sending quota')
  );
};
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  const rowNum = (j['row_number'] != null) ? Number(j['row_number']) : (j['Row'] != null && j['Row'] !== '') ? Number(j['Row']) : (2 + i);
  const sentVal = j[emailSentKey(j)];
  const sentStr = String(sentVal ?? '').toLowerCase().trim();
  if (sentStr === 'sent') {
    sent++;
    lastSentRow = Math.max(lastSentRow, rowNum);
  } else if (sentStr === 'error') {
    errors++;
    const errMsg = String(j[sendErrorKey(j)] ?? '').trim();
    if (errMsg && rowNum >= lastErrorRow) {
      lastErrorRow = rowNum;
      lastError = errMsg;
    }
    if (emailVal(j).length > 0) pending++;
  } else {
    if (emailVal(j).length > 0) pending++;
  }
}
const staticData = $getWorkflowStaticData('global');
const sheetKey = String(staticData.sendmailsCampaign?.sheetUrl || '').trim();
const cached = sheetKey && staticData.sendmailsLastErrorMap && staticData.sendmailsLastErrorMap[sheetKey]
  ? staticData.sendmailsLastErrorMap[sheetKey]
  : null;
if (cached?.message) {
  const cachedRow = cached.row != null ? Number(cached.row) : 0;
  if (!lastError || cachedRow >= lastErrorRow) {
    lastError = String(cached.message);
    lastErrorRow = cachedRow || lastErrorRow;
  }
}
const total = items.length;
const nextRowToSend = lastSentRow > 0 ? lastSentRow + 1 : 2;
return [{ json: { ok: true, sent, pending, errors, total, lastSentRow, nextRowToSend, lastError: lastError || null, lastErrorRow: lastErrorRow > 0 ? lastErrorRow : null, rateLimitHit: isRateLimitMsg(lastError) } }];

